#!/usr/bin/env python
import os
import sys
import tarfile
import zipfile
import subprocess
import time
from datetime import datetime

def create_backup(source_dir, output_format='tar.gz', output_dir=None):
    if not os.path.exists(source_dir):
        print("Error: Source directory does not exist: {}".format(source_dir))
        sys.exit(1)
    
    if not os.path.isdir(source_dir):
        print("Error: Source path is not a directory: {}".format(source_dir))
        sys.exit(1)
    
    source_dir = os.path.abspath(source_dir)
    dir_name = os.path.basename(source_dir)
    timestamp = datetime.now().strftime('%Y%m%d_%H%M%S')
    
    if output_dir is None:
        output_dir = os.getcwd()
    else:
        output_dir = os.path.abspath(output_dir)
        if not os.path.exists(output_dir):
            os.makedirs(output_dir)
    
    if output_format == 'tar.gz':
        archive_name = '{}_{}.tar.gz'.format(dir_name, timestamp)
        archive_path = os.path.join(output_dir, archive_name)
        create_tarball(source_dir, archive_path, 'gz')
    elif output_format == 'tar.bz2':
        archive_name = '{}_{}.tar.bz2'.format(dir_name, timestamp)
        archive_path = os.path.join(output_dir, archive_name)
        create_tarball(source_dir, archive_path, 'bz2')
    elif output_format == 'zip':
        archive_name = '{}_{}.zip'.format(dir_name, timestamp)
        archive_path = os.path.join(output_dir, archive_name)
        create_zip(source_dir, archive_path)
    elif output_format == '7z':
        archive_name = '{}_{}.7z'.format(dir_name, timestamp)
        archive_path = os.path.join(output_dir, archive_name)
        create_7z(source_dir, archive_path)
    else:
        print("Error: Unsupported format: {}".format(output_format))
        print("Supported formats: tar.gz, tar.bz2, zip, 7z")
        sys.exit(1)
    
    if os.path.exists(archive_path):
        file_size = os.path.getsize(archive_path)
        print("Backup created successfully:")
        print("  Archive: {}".format(archive_path))
        print("  Size: {} bytes ({:.2f} MB)".format(file_size, file_size / (1024.0 * 1024.0)))
        return archive_path
    else:
        print("Error: Failed to create backup archive")
        sys.exit(1)

def create_tarball(source_dir, archive_path, compression):
    mode_map = {'gz': 'w:gz', 'bz2': 'w:bz2'}
    mode = mode_map.get(compression, 'w:gz')
    
    print("Creating {} archive...".format(compression))
    parent_dir = os.path.dirname(source_dir)
    dir_name = os.path.basename(source_dir)
    
    original_cwd = os.getcwd()
    try:
        os.chdir(parent_dir)
        tar = tarfile.open(archive_path, mode)
        tar.add(dir_name)
        tar.close()
    finally:
        os.chdir(original_cwd)

def create_zip(source_dir, archive_path):
    print("Creating zip archive...")
    parent_dir = os.path.dirname(source_dir)
    dir_name = os.path.basename(source_dir)
    
    original_cwd = os.getcwd()
    try:
        os.chdir(parent_dir)
        zip_file = zipfile.ZipFile(archive_path, 'w', zipfile.ZIP_DEFLATED)
        
        for root, dirs, files in os.walk(dir_name):
            for file in files:
                file_path = os.path.join(root, file)
                zip_file.write(file_path)
        
        zip_file.close()
    finally:
        os.chdir(original_cwd)

def create_7z(source_dir, archive_path):
    print("Creating 7z archive...")
    
    try:
        subprocess.check_output(['7z', '--help'], stderr=subprocess.STDOUT)
        cmd = ['7z', 'a', '-t7z', archive_path, source_dir]
    except (OSError, subprocess.CalledProcessError):
        try:
            subprocess.check_output(['7za', '--help'], stderr=subprocess.STDOUT)
            cmd = ['7za', 'a', '-t7z', archive_path, source_dir]
        except (OSError, subprocess.CalledProcessError):
            print("Error: 7z command not found. Please install p7zip or p7zip-full")
            sys.exit(1)
    
    try:
        subprocess.check_call(cmd, stdout=subprocess.PIPE, stderr=subprocess.PIPE)
    except subprocess.CalledProcessError as e:
        print("Error: Failed to create 7z archive")
        sys.exit(1)

def main():
    if len(sys.argv) < 2:
        print("Usage: {} <directory_path> [format] [output_directory]".format(sys.argv[0]))
        print("Formats: tar.gz (default), tar.bz2, zip, 7z")
        print("Example: {} /home/user tar.gz /backup".format(sys.argv[0]))
        sys.exit(1)
    
    source_dir = sys.argv[1]
    output_format = sys.argv[2] if len(sys.argv) > 2 else 'tar.gz'
    output_dir = sys.argv[3] if len(sys.argv) > 3 else None
    
    create_backup(source_dir, output_format, output_dir)

if __name__ == '__main__':
    main()